  1	import * as React from 'react';
  2	import { referenceForModel, resourcePathFromModel } from '@odf/shared/utils';
  3	import { K8sKind } from '@openshift-console/dynamic-plugin-sdk/lib/api/common-types';
  4	import { Link } from 'react-router-dom-v5-compat';
  5	import {
  6	  Chart,
  7	  ChartAxis,
  8	  ChartBar,
  9	  ChartLabel,
 10	  ChartLegend,
 11	  ChartStack,
 12	  ChartThemeColor,
 13	  ChartTooltip,
 14	} from '@patternfly/react-charts/victory';
 15	import { Tooltip } from '@patternfly/react-core';
 16	import { BUCKETCLASSKIND, CLUSTERWIDE, OTHER } from './consts';
 17	import { getBarRadius, StackDataPoint } from './utils';
 18	import './breakdown-card.scss';
 19	
 20	export const LinkableLegend: React.FC<LinkableLegendProps> = React.memo(
 21	  (props: LinkableLegendProps) => {
 22	    const legendRef = React.useRef();
 23	
 24	    const { metricModel, datum, ocsVersion, odfNamespace } = props;
 25	    let href: string = metricModel
 26	      ? resourcePathFromModel(metricModel, datum.link, datum.ns)
 27	      : '';
 28	
 29	    /**
 30	     * "legendComponent" prop of "Chart" does not work if passed element is wrapped around a "div",
 31	     * Ref: https://developer.mozilla.org/en-US/docs/Web/SVG/Element/g#usage_notes.
 32	     * "Tooltip" is automatically wrapping its children around a "div" in PF5.
 33	     * Using "triggerRef" instead, as a workaround.
 34	     */
 35	    const customLegend = (
 36	      <>
 37	        <Tooltip content={datum.link} triggerRef={legendRef} />
 38	        <g ref={legendRef}>
 39	          <ChartLabel
 40	            {...props}
 41	            lineHeight={1.2}
 42	            style={[
 43	              { ...datum.labels, fontSize: 9 },
 44	              { fill: `var(--pf-t--global--text--color--subtle)`, fontSize: 8 },
 45	            ]}
 46	          />
 47	        </g>
 48	      </>
 49	    );
 50	    if (
 51	      datum.labelId === OTHER ||
 52	      datum.labelId === CLUSTERWIDE ||
 53	      !metricModel
 54	    ) {
 55	      return customLegend;
 56	    }
 57	    if (metricModel.kind === BUCKETCLASSKIND) {
 58	      if (ocsVersion && odfNamespace) {
 59	        href = `/k8s/ns/${odfNamespace}/clusterserviceversions/${ocsVersion}/${referenceForModel(
 60	          metricModel
 61	        )}/${datum.link}`;
 62	      } else {
 63	        return customLegend;
 64	      }
 65	    }
 66	    return (
 67	      <Link to={href} className="capacity-breakdown-card__legend-link">
 68	        {customLegend}
 69	      </Link>
 70	    );
 71	  }
 72	);
 73	
 74	LinkableLegend.displayName = 'LinkableLegend';
 75	
 76	export const BreakdownChart: React.FC<BreakdownChartProps> = ({
 77	  data,
 78	  legends,
 79	  metricModel,
 80	  ocsVersion,
 81	  labelPadding,
 82	  odfNamespace,
 83	}) => (
 84	  <Chart
 85	    legendPosition="bottom-left"
 86	    legendComponent={
 87	      <ChartLegend
 88	        themeColor={ChartThemeColor.multiOrdered}
 89	        data={legends}
 90	        y={40}
 91	        labelComponent={
 92	          <LinkableLegend
 93	            metricModel={metricModel}
 94	            ocsVersion={ocsVersion}
 95	            odfNamespace={odfNamespace}
 96	          />
 97	        }
 98	        orientation="horizontal"
 99	        symbolSpacer={7}
100	        gutter={10}
101	        height={50}
102	        style={{
103	          labels: Object.assign(
104	            { fontSize: 10 },
105	            labelPadding
106	              ? {
107	                  paddingRight: labelPadding.right,
108	                  paddingTop: labelPadding.top,
109	                  paddingBottom: labelPadding.bottom,
110	                  paddingLeft: labelPadding.left,
111	                }
112	              : {}
113	          ),
114	        }}
115	      />
116	    }
117	    height={60}
118	    padding={{
119	      bottom: 35,
120	      top: 0,
121	      right: 0,
122	      left: 0,
123	    }}
124	  >
125	    <ChartAxis
126	      style={{ axis: { stroke: 'none' }, ticks: { stroke: 'none' } }}
127	      tickFormat={() => ''}
128	    />
129	    <ChartStack horizontal>
130	      {data.map((d: StackDataPoint, index) => (
131	        <ChartBar
132	          key={d.id}
133	          style={{
134	            data: { stroke: 'white', strokeWidth: 0.7, fill: d.fill },
135	          }}
136	          cornerRadius={getBarRadius(index, data.length)}
137	          barWidth={12}
138	          padding={0}
139	          data={[d]}
140	          labelComponent={
141	            <ChartTooltip
142	              style={{ fontSize: 8, padding: 5 }}
143	              constrainToVisibleArea
144	            />
145	          }
146	        />
147	      ))}
148	    </ChartStack>
149	  </Chart>
150	);
151	
152	export type BreakdownChartProps = {
153	  data: StackDataPoint[];
154	  legends: any[];
155	  metricModel: K8sKind;
156	  ocsVersion?: string;
157	  labelPadding?: LabelPadding;
158	  odfNamespace?: string;
159	};
160	
161	export type LabelPadding = {
162	  left: number;
163	  right: number;
164	  bottom: number;
165	  top: number;
166	};
167	
